    suspend fun saveHealthGoals(goals: HealthGoals) {
        val docId = getUserDocId() ?: return
        try {
            db.collection("users")
                .document(docId)
                .collection("settings")
                .document("healthGoals")
                .set(goals)
                .await()
            Log.d(TAG, "Saved health goals: $goals")
        } catch (e: Exception) {
            Log.e(TAG, "Error saving health goals", e)
        }
    }

    suspend fun getHealthGoals(): HealthGoals {
        val docId = getUserDocId() ?: return HealthGoals()
        return try {
            val doc = db.collection("users")
                .document(docId)
                .collection("settings")
                .document("healthGoals")
                .get()
                .await()
            doc.toObject(HealthGoals::class.java) ?: HealthGoals()
        } catch (e: Exception) {
            Log.e(TAG, "Error getting health goals", e)
            HealthGoals()
        }
    }

    private suspend fun doStoreDailyData(
        steps: Long, distanceMeters: Double, activeTimeMin: Long, date: String
    ) {
        val uid = auth.currentUser?.uid ?: return
        val docRef = db.collection("users").document(uid).collection("dailyLogs").document(date)

        try {
            val nowMs = Clock.System.now().toEpochMilliseconds()
            val updates = mapOf(
                "steps" to steps,
                "distanceMeters" to distanceMeters,
                "activeTimeMins" to activeTimeMin,
                "lastHealthSync" to nowMs
            )
            docRef.set(updates, SetOptions.merge()).await()

            // Update achievement progress for Steps
            val goals = getHealthGoals()
            val stepsGoal = goals.stepsGoal
            if (steps >= stepsGoal) {
                // Award achievement - requires injection of use case eventually, ignore for now to fix build quickly as this is a singleton
                // TODO: Update via UseCase 
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error storing daily data", e)
        }
    }
}

package com.example.myapplication.data.nutrition

import com.example.myapplication.network.FatSecretApi
import com.example.myapplication.network.FoodDetail
import com.example.myapplication.network.FoodSummary
import com.example.myapplication.network.RecipeDetail
import com.example.myapplication.network.RecipeSummary
import com.example.myapplication.persistence.FirestoreHelper
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.tasks.await

/**
 * Singleton implementacija repozitorija,
 * ki skrbi tako za FatSecret API Iskanje kot za Firestore logiranje.
 * UI ne sme več sam logirati v bazo.
 */
object FoodRepositoryImpl {

    suspend fun searchFoodByName(query: String, maxResults: Int = 20): List<FoodSummary> {
        return FatSecretApi.searchFoods(query, 1, maxResults)
    }

    suspend fun getFoodAutocomplete(query: String, maxResults: Int = 5): List<String> {
        return FatSecretApi.getFoodAutocomplete(query, maxResults).map { it.suggestion }
    }

    suspend fun getFoodDetail(id: String): FoodDetail {
        return FatSecretApi.getFoodDetail(id)
    }

    suspend fun searchRecipes(query: String, maxResults: Int = 20): List<RecipeSummary> {
        return FatSecretApi.searchRecipes(query, 1, maxResults)
    }

    suspend fun getRecipeDetail(id: String): RecipeDetail {
        return FatSecretApi.getRecipeDetail(id)
    }

    suspend fun logCustomMeal(name: String, itemsList: List<Any>): String {
        val docRef = FirestoreHelper.getCurrentUserDocRef()
        val mealData = mapOf(
            "name" to name,
            "items" to itemsList,
            "createdAt" to com.google.firebase.firestore.FieldValue.serverTimestamp()
        )

        // Zamenjavo klasičnega .add na Batch ali Transaction
        return FirebaseFirestore.getInstance().runTransaction { transaction ->
            val newRef = docRef.collection("customMeals").document()
            transaction.set(newRef, mealData)
            newRef.id
        }.await()
    }

    suspend fun deleteCustomMeal(mealId: String) {
        val docRef = FirestoreHelper.getCurrentUserDocRef()
        val mealRef = docRef.collection("customMeals").document(mealId)

        FirebaseFirestore.getInstance().runTransaction { transaction ->
            transaction.delete(mealRef)
        }.await()
    }

    fun observeCustomMeals(uid: String, onData: (com.google.firebase.firestore.QuerySnapshot?) -> Unit): com.google.firebase.firestore.ListenerRegistration {
        return FirebaseFirestore.getInstance()
            .collection("users").document(uid)
            .collection("customMeals")
            .addSnapshotListener { snaps, _ -> onData(snaps) }
    }

    fun observeDailyLog(uid: String, todayId: String, onData: (com.google.firebase.firestore.DocumentSnapshot?) -> Unit): com.google.firebase.firestore.ListenerRegistration {
        return FirebaseFirestore.getInstance()
            .collection("users").document(uid)
            .collection("dailyLogs").document(todayId)
            .addSnapshotListener { doc, _ -> onData(doc) }
    }
}

package com.example.myapplication.data.nutrition

import com.example.myapplication.network.FatSecretApi
import com.example.myapplication.network.FoodDetail
import com.example.myapplication.network.FoodSummary
import com.example.myapplication.network.RecipeDetail
import com.example.myapplication.network.RecipeSummary
import com.example.myapplication.persistence.FirestoreHelper
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.tasks.await
import kotlinx.datetime.Clock

/**
 * Singleton implementacija repozitorija,
 * ki skrbi tako za FatSecret API Iskanje kot za Firestore logiranje.
 * UI ne sme več sam logirati v bazo.
 */
object FoodRepositoryImpl {

    suspend fun searchFoodByName(query: String, maxResults: Int = 20): List<FoodSummary> {
        return FatSecretApi.searchFoods(query, 1, maxResults)
    }

    suspend fun getFoodAutocomplete(query: String, maxResults: Int = 5): List<String> {
        return FatSecretApi.getFoodAutocomplete(query, maxResults).map { it.suggestion }
    }

    suspend fun getFoodDetail(id: String): FoodDetail {
        return FatSecretApi.getFoodDetail(id)
    }

    suspend fun searchRecipes(query: String, maxResults: Int = 20): List<RecipeSummary> {
        return FatSecretApi.searchRecipes(query, 1, maxResults)
    }

    suspend fun getRecipeDetail(id: String): RecipeDetail {
        return FatSecretApi.getRecipeDetail(id)
    }

    suspend fun logCustomMeal(name: String, itemsList: List<Any>): String {
        val docRef = FirestoreHelper.getCurrentUserDocRef()
        val mealData = mapOf(
            "name" to name,
            "items" to itemsList,
            "createdAt" to com.google.firebase.firestore.FieldValue.serverTimestamp()
        )

        // Zamenjavo klasičnega .add na Batch ali Transaction
        return FirebaseFirestore.getInstance().runTransaction { transaction ->
            val newRef = docRef.collection("customMeals").document()
            transaction.set(newRef, mealData)
            newRef.id
        }.await()
    }

    suspend fun deleteCustomMeal(mealId: String) {
        val docRef = FirestoreHelper.getCurrentUserDocRef()
        val mealRef = docRef.collection("customMeals").document(mealId)

        FirebaseFirestore.getInstance().runTransaction { transaction ->
            transaction.delete(mealRef)
        }.await()
    }

    fun observeCustomMeals(uid: String, onData: (com.google.firebase.firestore.QuerySnapshot?) -> Unit): com.google.firebase.firestore.ListenerRegistration {
        return FirebaseFirestore.getInstance()
            .collection("users").document(uid)
            .collection("customMeals")
            .addSnapshotListener { snaps, _ -> onData(snaps) }
    }

    fun observeDailyLog(uid: String, todayId: String, onData: (com.google.firebase.firestore.DocumentSnapshot?) -> Unit): com.google.firebase.firestore.ListenerRegistration {
        return FirebaseFirestore.getInstance()
            .collection("users").document(uid)
            .collection("dailyLogs").document(todayId)
            .addSnapshotListener { doc, _ -> onData(doc) }
    }
}

package com.example.myapplication.data.settings

import android.content.Context
import android.content.SharedPreferences

/**
 *  TODO (KMP MIGRATION):
 * This repository isolates Android's SharedPreferences.
 * To make the app KMP-ready, replace `SharedPreferences` with `androidx.datastore.preferences.core`
 * or `russhwolf:multiplatform-settings`.
 */
class UserPreferencesRepository(private val context: Context) {

    private val userPrefs: SharedPreferences by lazy {
        context.getSharedPreferences("user_prefs", Context.MODE_PRIVATE)
    }

    private val algoPrefs: SharedPreferences by lazy {
        context.getSharedPreferences("algorithm_prefs", Context.MODE_PRIVATE)
    }

    private val widgetPrefs: SharedPreferences by lazy {
        context.getSharedPreferences("app_flags", Context.MODE_PRIVATE)
    }

    // Example methods for migrating shared preference usages

    fun isDarkModeEnabled(): Boolean {
        return userPrefs.getBoolean("dark_mode", true)
    }

    fun setDarkModeEnabled(enabled: Boolean) {
        userPrefs.edit().putBoolean("dark_mode", enabled).apply()
    }

    fun isFreshStartOnLogin(): Boolean {
        return widgetPrefs.getBoolean("fresh_start_on_login", false)
    }

    fun setFreshStartOnLogin(freshStart: Boolean) {
        widgetPrefs.edit().putBoolean("fresh_start_on_login", freshStart).apply()
    }

    fun clearAllSettings() {
        val prefNames = listOf(
            "user_prefs", "body_module", "nutrition_xp", "bm_prefs",
            "smartwatch_prefs", "algorithm_prefs", "weight_widget_prefs",
            "water_widget_prefs", "food_cache", "water_cache", "burned_cache",
            "daily_sync_prefs", "streak_widget_prefs", "app_flags"
        )
        for (name in prefNames) {
            context.getSharedPreferences(name, Context.MODE_PRIVATE).edit().clear().apply()
        }
        setFreshStartOnLogin(true)
    }
}

