import androidx.compose.ui.text.input.KeyboardType
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.google.firebase.firestore.FieldValue
import com.google.firebase.firestore.ktx.firestore
import com.google.firebase.ktx.Firebase
import java.time.LocalDate

/**
 * Transparent Activity that shows a weight input dialog from widget.
 * Closes immediately after user saves or cancels.
 */
class WeightInputActivity : ComponentActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Make activity transparent and show behind lockscreen if needed
        window.setFlags(
            WindowManager.LayoutParams.FLAG_NOT_TOUCH_MODAL,
            WindowManager.LayoutParams.FLAG_NOT_TOUCH_MODAL
        )

        setContent {
            MaterialTheme {
                WeightInputDialog(
                    onDismiss = { finish() },
                    onSaved = { finish() }
                )
            }
        }
    }

    @Composable
    private fun WeightInputDialog(onDismiss: () -> Unit, onSaved: () -> Unit) {
        val context = LocalContext.current
        // uid v remember{} — ne sme se klicati ob vsakem recomposition
        val uid = remember { com.example.myapplication.persistence.FirestoreHelper.getCurrentUserDocId() }
        var weightInput by remember { mutableStateOf("") }
        var saving by remember { mutableStateOf(false) }
        var errorMessage by remember { mutableStateOf<String?>(null) }

        if (uid == null) {
            // Not logged in - show error and close
            LaunchedEffect(Unit) {
                errorMessage = "Please log in first"
                kotlinx.coroutines.delay(2000)
                onDismiss()
            }
        }

        AlertDialog(
            onDismissRequest = { if (!saving) onDismiss() },
            title = { Text("Enter Weight") },
            text = {
                Column(verticalArrangement = Arrangement.spacedBy(12.dp)) {
                    OutlinedTextField(
                        value = weightInput,
                        onValueChange = {
                            weightInput = it.filter { c -> c.isDigit() || c == '.' }.take(6)
                            errorMessage = null
                        },
                        placeholder = { Text("e.g. 75.3 kg") },
                        singleLine = true,
                        keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                        isError = errorMessage != null,
                        modifier = Modifier.fillMaxWidth()
                    )
                    if (errorMessage != null) {
                        Text(
                            text = errorMessage!!,
                            color = MaterialTheme.colorScheme.error,
                            fontSize = 12.sp
                        )
                    }
                    Text("Date: ${LocalDate.now()}", fontSize = 12.sp, color = MaterialTheme.colorScheme.onSurfaceVariant)
                }
            },
            confirmButton = {
                TextButton(
                    enabled = !saving && weightInput.isNotBlank(),
                    onClick = {
                        val w = weightInput.toDoubleOrNull()
                        if (w == null || w <= 0) {
                            errorMessage = "Please enter valid weight"
                            return@TextButton
                        }
                        if (uid == null) {
                            errorMessage = "Not logged in"
                            return@TextButton
                        }

                        saving = true
                        val today = LocalDate.now().toString()
                        val db = Firebase.firestore

                        // Save to weightLogs (for chart) — merge: ne izbriši obstoječih polj
                        db.collection("users").document(uid).collection("weightLogs").document(today)
                            .set(
                                mapOf("date" to today, "weightKg" to w, "updatedAt" to FieldValue.serverTimestamp()),
                                com.google.firebase.firestore.SetOptions.merge()
                            )
                            .addOnSuccessListener {
                                Log.d("WeightInput", "Saved to weightLogs: $w kg")

                                // Save to dailyMetrics (for widget)
                                db.collection("users").document(uid).collection("dailyMetrics").document(today)
                                    .set(
                                        mapOf("date" to today, "weight" to w.toFloat(), "updatedAt" to FieldValue.serverTimestamp()),
                                        com.google.firebase.firestore.SetOptions.merge()
                                    )
                                    .addOnSuccessListener {
                                        Log.d("WeightInput", "Saved to dailyMetrics: $w kg")
                                        // Update widget
                                        WeightWidgetProvider.updateWidgetFromApp(context, w.toFloat())
                                        onSaved()
                                    }
                                    .addOnFailureListener { e ->
                                        Log.e("WeightInput", "Failed to save to dailyMetrics", e)
                                        errorMessage = "Save failed"
                                        saving = false
                                    }
                            }
                            .addOnFailureListener { e ->
                                Log.e("WeightInput", "Failed to save to weightLogs", e)
                                errorMessage = "Save failed"
                                saving = false
                            }
                    }
                ) { Text(if (saving) "Saving..." else "Save") }
            },
            dismissButton = {
                TextButton(onClick = { if (!saving) onDismiss() }) { Text("Cancel") }
            }
        )
    }
}

